﻿using System;
using System.Collections;
using System.IO;
using UnityEditor;
using UnityEngine.AIGraph.Backend;
using UnityEngine.AIGraph.Cache;


#if UNITY_EDITOR
#endif

namespace UnityEngine.AIGraph
{
    [Serializable]
    public class RodinMaterialData : IReceivedData
    {
        public string prompt;
        public string url;

        public string hdrPath;

        private Material material;

        public RodinMaterialData()
        {
        }

        public override Object transferToUnityObject()
        {
            return material;
        }

        public Object GetStaticPreview()
        {
            return ImportUtils.Import<Texture2D>(hdrPath);
        }

        public override IEnumerator GetDefaultPreview(Action<Texture2D> callback)
        {
            callback?.Invoke(GetStaticPreview() as Texture2D);
            yield return null;
        }

        public override IEnumerator RetrieveFromBackend(int serverIndex)
        {
            var jobStatusRestCall = new GetJobStatusRestCall<RodinSkyboxRequest, RodinImageOutput>(
                serverConfig, serverIndex, ID);
            var jobInfoRequest = new TaskStatusRequest();

            var processor = new CoroutineProcessor<RodinImageOutput>();
            yield return processor.ProcessAsync(BackendUtils.RetrieveFromBackendCommon(
                jobStatusRestCall, jobInfoRequest, progressCallback));
            var output = processor.Result;

            tokenRemaining = jobStatusRestCall.Result.creditBalance;
            if (!string.IsNullOrEmpty(output.hdr))
                url = output.hdr;
            else if (!string.IsNullOrEmpty(output.skybox_basic))
                url = output.skybox_basic;
            if (string.IsNullOrEmpty(url))
                throw new NullReferenceException($"No valid image in response, task: {ID}");
            var imgCoroutine = BackendUtils.DownloadFromUrl(url, serverIndex);
            yield return imgCoroutine;
            var img = imgCoroutine.Current as byte[];
            if (assetPath.EndsWith(".mat"))
                assetPath = assetPath[..^4];
            hdrPath = assetPath + "_baseMap";
            var ext = PathUtils.GetUrlExtension(url);
            if (!string.IsNullOrEmpty(ext) && !hdrPath.EndsWith(ext))
                hdrPath += ext;
            BackendUtils.SaveBytesToFile(img, hdrPath);
            if (material == null)
            {
                var ti = (TextureImporter)AssetImporter.GetAtPath(hdrPath);
                ti.mipmapEnabled = false;
                ti.streamingMipmaps = false;
                ti.SaveAndReimport();
                var shader = Shader.Find("Skybox/Panoramic");
                material = new Material(shader)
                {
                    mainTexture = ImportUtils.Import<Texture2D>(hdrPath)
                };
                assetPath = ExportUtils.SaveAsset(material, Path.GetDirectoryName(assetPath),
                    Path.GetFileName(assetPath), ExportUtils.OverwriteAction.Overwrite);
                material = ImportUtils.Import<Material>(assetPath);
            }
            else
                material.mainTexture = ImportUtils.Import<Texture2D>(hdrPath);

            yield return null;
        }
    }
}

