using UnityEngine;
using UnityEngine.UI;
using System.Collections.Generic;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class QuestPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _questPanel;
        [SerializeField] private Button _closeButton;

        [Header("Tabs")]
        [SerializeField] private Button _tabDaily;
        [SerializeField] private Button _tabMain;
        [SerializeField] private Button _tabAchievement;
        [SerializeField] private Button _tabEvent;
        [SerializeField] private Color _tabActiveColor = new Color(1f, 0.78f, 0.2f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.3f, 0.6f, 0.3f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _questItemPrefab;

        [Header("Info Bar")]
        [SerializeField] private Text _resetTimerText;
        [SerializeField] private Text _activityText;

        [Header("Activity Bar")]
        [SerializeField] private Slider _activitySlider;
        [SerializeField] private Image[] _chestIcons;
        [SerializeField] private Sprite _chestLocked;
        [SerializeField] private Sprite _chestUnlocked;
        [SerializeField] private Sprite _chestClaimed;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/QuestItems";

        private QuestData _questData;
        private QuestCategory _currentCategory;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<QuestCategory, Button> _tabButtons = new Dictionary<QuestCategory, Button>();
        private GameObject _torchRoot;
        private MovingClouds _clouds;
        private ParticleSystem _snowParticles;
        private int _snowOriginalSortOrder;

        public void SetReferences(GameObject questPanel, Button closeButton, Button tabDaily, Button tabMain, Button tabAchievement, Button tabEvent, Transform itemContainer, GameObject questItemPrefab, Text resetTimerText, Text activityText, Slider activitySlider, Image[] chestIcons)
        {
            _questPanel = questPanel;
            _closeButton = closeButton;
            _tabDaily = tabDaily;
            _tabMain = tabMain;
            _tabAchievement = tabAchievement;
            _tabEvent = tabEvent;
            _itemContainer = itemContainer;
            _questItemPrefab = questItemPrefab;
            _resetTimerText = resetTimerText;
            _activityText = activityText;
            _activitySlider = activitySlider;
            _chestIcons = chestIcons;
        }

        private void Awake()
        {
            _tabButtons[QuestCategory.Daily] = _tabDaily;
            _tabButtons[QuestCategory.Main] = _tabMain;
            _tabButtons[QuestCategory.Achievement] = _tabAchievement;
            _tabButtons[QuestCategory.Event] = _tabEvent;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(CloseQuest);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                }
            }

            _torchRoot = GameObject.Find("火把");

            GameObject bgObj = GameObject.Find("背景");
            if (bgObj != null)
            {
                _clouds = bgObj.GetComponent<MovingClouds>();
                _snowParticles = bgObj.GetComponentInChildren<ParticleSystem>();
                if (_snowParticles != null)
                {
                    var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                    if (renderer != null)
                        _snowOriginalSortOrder = renderer.sortingOrder;
                }
            }

            LoadQuestData();
        }

        private void Start()
        {
            if (_questPanel != null)
                _questPanel.SetActive(false);
        }

        private void LoadQuestData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _questData = JsonUtility.FromJson<QuestData>(jsonFile.text);
                Debug.Log($"[QuestPanel] Loaded {_questData.items.Length} quests from JSON");
            }
            else
            {
                Debug.LogError($"[QuestPanel] Failed to load JSON: Resources/{_jsonPath}");
                _questData = new QuestData { items = new QuestItemData[0], dailyActivity = 0, dailyActivityMax = 120 };
            }
        }

        public void OpenQuest()
        {
            if (_questPanel != null)
                _questPanel.SetActive(true);

            if (_torchRoot != null)
                _torchRoot.SetActive(false);

            if (_clouds != null)
                _clouds.IsPaused = true;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = -10;
                _snowParticles.Pause(true);
            }

            LoadQuestData();
            SwitchTab(QuestCategory.Daily);
        }

        public void CloseQuest()
        {
            if (_questPanel != null)
                _questPanel.SetActive(false);

            if (_torchRoot != null)
                _torchRoot.SetActive(true);

            if (_clouds != null)
                _clouds.IsPaused = false;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = _snowOriginalSortOrder;
                _snowParticles.Play(true);
            }
        }

        private void SwitchTab(QuestCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            RefreshItemList();
            UpdateInfoBar();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory ? _tabActiveColor : new Color(0.8f, 0.8f, 0.8f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void UpdateInfoBar()
        {
            if (_activityText != null && _questData != null)
                _activityText.text = $"⭐ {_questData.dailyActivity}";

            if (_activitySlider != null && _questData != null)
            {
                _activitySlider.maxValue = _questData.dailyActivityMax;
                _activitySlider.value = _questData.dailyActivity;
            }

            UpdateChestIcons();
        }

        private void UpdateChestIcons()
        {
            if (_questData == null || _chestIcons == null) return;
            int[] thresholds = { 30, 60, 90, 120 };
            for (int i = 0; i < _chestIcons.Length && i < thresholds.Length; i++)
            {
                if (_chestIcons[i] == null) continue;
                _chestIcons[i].sprite = _questData.dailyActivity >= thresholds[i] ? _chestUnlocked : _chestLocked;
            }
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) DestroyImmediate(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _questItemPrefab == null)
            {
                Debug.LogWarning("[QuestPanel] Item container or prefab is null");
                return;
            }

            foreach (var questData in _questData.items)
            {
                if (questData.category != _currentCategory) continue;

                GameObject itemObj = Instantiate(_questItemPrefab, _itemContainer);
                itemObj.SetActive(true);
                _spawnedItems.Add(itemObj);

                var questItemUI = itemObj.GetComponent<QuestItemUI>();
                if (questItemUI != null)
                    questItemUI.Setup(questData, this);
            }
        }

        public void OnClaimClicked(QuestItemData questData)
        {
            if (questData.status != QuestStatus.Claimable)
            {
                Debug.Log($"[QuestPanel] {questData.name} 不可领取");
                return;
            }

            var wallet = PlayerWallet.Instance;
            if (wallet == null)
            {
                Debug.LogWarning("[QuestPanel] PlayerWallet not found");
                return;
            }

            if (questData.rewards != null)
            {
                foreach (var reward in questData.rewards)
                {
                    switch (reward.rewardType)
                    {
                        case RewardType.Gold: wallet.AddGold(reward.amount); break;
                        case RewardType.Diamond: wallet.AddDiamond(reward.amount); break;
                        case RewardType.Stamina: wallet.AddStamina(reward.amount); break;
                    }
                }
            }

            questData.status = QuestStatus.Claimed;
            _questData.dailyActivity += 10;
            Debug.Log($"[QuestPanel] 领取成功: {questData.name}");

            RefreshItemList();
            UpdateInfoBar();
        }

        public void OnGoToClicked(QuestItemData questData)
        {
            Debug.Log($"[QuestPanel] 前往: {questData.name}");
            CloseQuest();
        }

        public static string GetCategoryName(QuestCategory category)
        {
            return category switch
            {
                QuestCategory.Daily => "每日任务",
                QuestCategory.Main => "主线任务",
                QuestCategory.Achievement => "成就任务",
                QuestCategory.Event => "活动任务",
                _ => "未知"
            };
        }

        public static string GetRewardSymbol(RewardType type)
        {
            return type switch
            {
                RewardType.Gold => "🪙",
                RewardType.Diamond => "💎",
                RewardType.Stamina => "⚡",
                RewardType.Item => "📦",
                _ => ""
            };
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class QuestItemUI : MonoBehaviour
    {
        [Header("UI References")]
        [SerializeField] private Image _iconImage;
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _descText;
        [SerializeField] private Slider _progressSlider;
        [SerializeField] private Text _progressText;
        [SerializeField] private Image _rewardIcon;
        [SerializeField] private Text _rewardText;
        [SerializeField] private Button _actionButton;
        [SerializeField] private Text _actionText;
        [SerializeField] private GameObject _tagObject;
        [SerializeField] private Text _tagText;

        private QuestItemData _itemData;
        private QuestPanel _questPanel;

        public void SetReferences(Image iconImage, Text nameText, Text descText, Slider progressSlider, Text progressText, Image rewardIcon, Text rewardText, Button actionButton, Text actionText, GameObject tagObject, Text tagText)
        {
            _iconImage = iconImage;
            _nameText = nameText;
            _descText = descText;
            _progressSlider = progressSlider;
            _progressText = progressText;
            _rewardIcon = rewardIcon;
            _rewardText = rewardText;
            _actionButton = actionButton;
            _actionText = actionText;
            _tagObject = tagObject;
            _tagText = tagText;
        }

        public void Setup(QuestItemData itemData, QuestPanel questPanel)
        {
            _itemData = itemData;
            _questPanel = questPanel;

            // Name & Description
            if (_nameText != null)
                _nameText.text = itemData.name;

            if (_descText != null)
                _descText.text = itemData.description;

            // Progress
            if (_progressSlider != null)
            {
                _progressSlider.maxValue = itemData.targetCount;
                _progressSlider.value = itemData.currentCount;
            }

            if (_progressText != null)
                _progressText.text = $"{itemData.currentCount}/{itemData.targetCount}";

            // Icon
            if (_iconImage != null)
            {
                if (!string.IsNullOrEmpty(itemData.iconPath))
                {
                    var sprite = Resources.Load<Sprite>(itemData.iconPath);
                    if (sprite != null)
                    {
                        _iconImage.sprite = sprite;
                        _iconImage.color = Color.white;
                    }
                    else
                    {
                        SetCategoryFallbackColor(itemData.category);
                    }
                }
                else
                {
                    SetCategoryFallbackColor(itemData.category);
                }
            }

            // Reward
            if (itemData.rewards != null && itemData.rewards.Length > 0)
            {
                var reward = itemData.rewards[0];
                if (_rewardText != null)
                    _rewardText.text = $"x{reward.amount}";
            }

            // Tag
            if (_tagObject != null)
            {
                bool hasTag = !string.IsNullOrEmpty(itemData.tag);
                _tagObject.SetActive(hasTag);
                if (hasTag && _tagText != null)
                    _tagText.text = itemData.tag;
            }

            // Action Button
            if (_actionButton != null)
            {
                _actionButton.onClick.RemoveAllListeners();

                if (itemData.status == QuestStatus.Claimed)
                {
                    _actionButton.interactable = false;
                    if (_actionText != null)
                        _actionText.text = "已完成";
                }
                else if (itemData.status == QuestStatus.Claimable)
                {
                    _actionButton.interactable = true;
                    if (_actionText != null)
                        _actionText.text = "领取";

                    var colors = _actionButton.colors;
                    colors.normalColor = new Color(1f, 0.65f, 0.15f, 1f);
                    colors.highlightedColor = new Color(1f, 0.75f, 0.3f, 1f);
                    _actionButton.colors = colors;

                    _actionButton.onClick.AddListener(OnClaimClicked);
                }
                else
                {
                    _actionButton.interactable = true;
                    if (_actionText != null)
                        _actionText.text = "前往";

                    var colors = _actionButton.colors;
                    colors.normalColor = new Color(0.3f, 0.75f, 0.3f, 1f);
                    colors.highlightedColor = new Color(0.4f, 0.85f, 0.4f, 1f);
                    _actionButton.colors = colors;

                    _actionButton.onClick.AddListener(OnGoToClicked);
                }
            }
        }

        private void SetCategoryFallbackColor(QuestCategory category)
        {
            _iconImage.sprite = null;
            _iconImage.color = category switch
            {
                QuestCategory.Daily => new Color(1f, 0.85f, 0.2f, 1f),
                QuestCategory.Main => new Color(0.3f, 0.7f, 1f, 1f),
                QuestCategory.Achievement => new Color(0.8f, 0.5f, 1f, 1f),
                QuestCategory.Event => new Color(1f, 0.4f, 0.4f, 1f),
                _ => Color.white
            };
        }

        private void OnClaimClicked()
        {
            if (_questPanel != null && _itemData != null)
                _questPanel.OnClaimClicked(_itemData);
        }

        private void OnGoToClicked()
        {
            if (_questPanel != null && _itemData != null)
                _questPanel.OnGoToClicked(_itemData);
        }
    }
}

using UnityEngine;

namespace TowerDefense.Data
{
    public enum QuestCategory
    {
        Daily,      // 每日任务
        Main,       // 主线任务
        Achievement,// 成就任务
        Event       // 活动任务
    }

    public enum QuestStatus
    {
        Locked,     // 未解锁
        InProgress, // 进行中
        Claimable,  // 可领取
        Claimed     // 已领取
    }

    public enum RewardType
    {
        Gold,
        Diamond,
        Stamina,
        Item
    }

    [System.Serializable]
    public class QuestReward
    {
        public RewardType rewardType;
        public int amount;
        public string itemPath; // RewardType.Item 时的物品路径
    }

    [System.Serializable]
    public class QuestItemData
    {
        public int id;
        public string name;
        public string description;
        public QuestCategory category;
        public string iconPath;
        public int targetCount;       // 目标数量
        public int currentCount;      // 当前进度
        public QuestStatus status;
        public QuestReward[] rewards;
        public string tag;            // 标签 (如 "hot", "new")
    }

    [System.Serializable]
    public class QuestData
    {
        public QuestItemData[] items;
        public int dailyActivity;     // 今日活跃度
        public int dailyActivityMax;   // 每日活跃度上限
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class GameUI : MonoBehaviour
    {
        [Header("Top Bar")]
        [SerializeField] private Image _goldIcon;
        [SerializeField] private Text _goldText;
        [SerializeField] private Image _lifeIcon;
        [SerializeField] private Text _lifeText;
        [SerializeField] private Image _waveIcon;
        [SerializeField] private Text _waveText;

        [Header("Wave Info")]
        [SerializeField] private GameObject _waveInfoPanel;
        [SerializeField] private Text _waveTimerText;
        [SerializeField] private Text _enemyCountText;
        [SerializeField] private Button _startWaveButton;

        [Header("Tower Selection")]
        [SerializeField] private GameObject _towerSelectPanel;
        [SerializeField] private Transform _towerButtonContainer;
        [SerializeField] private GameObject _towerButtonPrefab;

        [Header("Tower Info")]
        [SerializeField] private GameObject _towerInfoPanel;
        [SerializeField] private Text _towerNameText;
        [SerializeField] private Text _towerLevelText;
        [SerializeField] private Text _towerDamageText;
        [SerializeField] private Button _upgradeButton;
        [SerializeField] private Text _upgradeCostText;
        [SerializeField] private Button _sellButton;
        [SerializeField] private Text _sellValueText;

        [Header("Game Controls")]
        [SerializeField] private Button _pauseButton;
        [SerializeField] private Button _speedButton;
        [SerializeField] private GameObject _pauseMenu;
        [SerializeField] private GameObject _gameOverPanel;
        [SerializeField] private GameObject _victoryPanel;

        [Header("Settings")]
        [SerializeField] private Slider _volumeSlider;
        [SerializeField] private Toggle _soundToggle;

        private Tower.TowerSlot _selectedSlot;
        private Tower.Tower _selectedTower;

        private void Start()
        {
            InitializeUI();
            SubscribeToEvents();
        }

        private void InitializeUI()
        {
            if (_pauseMenu != null) _pauseMenu.SetActive(false);
            if (_gameOverPanel != null) _gameOverPanel.SetActive(false);
            if (_victoryPanel != null) _victoryPanel.SetActive(false);
            if (_towerInfoPanel != null) _towerInfoPanel.SetActive(false);
            if (_towerSelectPanel != null) _towerSelectPanel.SetActive(false);

            UpdateGoldDisplay(GameManager.Instance.CurrentGold);
            UpdateLifeDisplay(GameManager.Instance.CurrentLife);
            UpdateWaveDisplay(GameManager.Instance.CurrentWave);

            if (_startWaveButton != null)
            {
                _startWaveButton.onClick.AddListener(OnStartWaveClicked);
            }
            if (_pauseButton != null)
            {
                _pauseButton.onClick.AddListener(OnPauseClicked);
            }
            if (_speedButton != null)
            {
                _speedButton.onClick.AddListener(OnSpeedClicked);
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.onClick.AddListener(OnUpgradeClicked);
            }
            if (_sellButton != null)
            {
                _sellButton.onClick.AddListener(OnSellClicked);
            }
        }

        private void SubscribeToEvents()
        {
            GameManager.Instance.OnGoldChanged += UpdateGoldDisplay;
            GameManager.Instance.OnLifeChanged += UpdateLifeDisplay;
            GameManager.Instance.OnWaveChanged += UpdateWaveDisplay;
            GameManager.Instance.OnStateChanged += OnGameStateChanged;

            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Subscribe<LifeChangedEvent>(OnLifeChanged);
        }

        private void OnDestroy()
        {
            if (GameManager.Instance != null)
            {
                GameManager.Instance.OnGoldChanged -= UpdateGoldDisplay;
                GameManager.Instance.OnLifeChanged -= UpdateLifeDisplay;
                GameManager.Instance.OnWaveChanged -= UpdateWaveDisplay;
                GameManager.Instance.OnStateChanged -= OnGameStateChanged;
            }

            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Unsubscribe<LifeChangedEvent>(OnLifeChanged);
        }

        #region Display Updates

        private void UpdateGoldDisplay(int gold)
        {
            if (_goldText != null)
            {
                _goldText.text = gold.ToString();
            }

            if (_goldIcon != null)
            {
                _goldIcon.enabled = true;
            }
        }

        private void UpdateLifeDisplay(int life)
        {
            if (_lifeText != null)
            {
                _lifeText.text = life.ToString();
            }

            if (_lifeIcon != null)
            {
                _lifeIcon.enabled = true;
            }
        }

        private void UpdateWaveDisplay(int wave)
        {
            if (_waveText != null)
            {
                _waveText.text = $"{wave}/{GameManager.Instance.TotalWaves}";
            }

            if (_waveIcon != null)
            {
                _waveIcon.enabled = true;
            }
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            UpdateGoldDisplay(e.CurrentGold);
        }

        private void OnLifeChanged(LifeChangedEvent e)
        {
            UpdateLifeDisplay(e.CurrentLife);
        }

        #endregion

        #region Tower Selection

        public void ShowTowerSelectPanel(Tower.TowerSlot slot)
        {
            _selectedSlot = slot;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(true);
            }
        }

        public void HideTowerSelectPanel()
        {
            _selectedSlot = null;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(false);
            }
        }

        public void SelectTower(Data.TowerData towerData)
        {
            if (_selectedSlot != null)
            {
                _selectedSlot.PlaceTower(towerData);
                HideTowerSelectPanel();
            }
        }

        #endregion

        #region Tower Info

        public void ShowTowerInfo(Tower.Tower tower)
        {
            _selectedTower = tower;

            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(true);
            }

            UpdateTowerInfo();
        }

        public void HideTowerInfo()
        {
            _selectedTower = null;
            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(false);
            }
        }

        private void UpdateTowerInfo()
        {
            if (_selectedTower == null) return;

            if (_towerNameText != null)
            {
                _towerNameText.text = _selectedTower.Data.towerName;
            }
            if (_towerLevelText != null)
            {
                _towerLevelText.text = $"Level: {_selectedTower.CurrentLevel}";
            }
            if (_towerDamageText != null)
            {
                _towerDamageText.text = $"Damage: {_selectedTower.CurrentStats.damage}";
            }
            if (_upgradeCostText != null)
            {
                int cost = _selectedTower.GetUpgradeCost();
                _upgradeCostText.text = cost > 0 ? cost.ToString() : "MAX";
            }
            if (_sellValueText != null)
            {
                _sellValueText.text = _selectedTower.GetSellValue().ToString();
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.interactable = !_selectedTower.IsMaxLevel;
            }
        }

        #endregion

        #region Button Handlers

        private void OnStartWaveClicked()
        {
            Wave.WaveManager waveManager = FindObjectOfType<Wave.WaveManager>();
            if (waveManager != null)
            {
                waveManager.ForceStartWave();
            }

            if (_startWaveButton != null)
            {
                _startWaveButton.gameObject.SetActive(false);
            }
        }

        private void OnPauseClicked()
        {
            GameManager.Instance.TogglePause();

            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(GameManager.Instance.CurrentState == GameState.Paused);
            }
        }

        private void OnSpeedClicked()
        {
            float currentSpeed = GameManager.Instance.GameSpeed;
            float newSpeed = currentSpeed >= 3f ? 1f : currentSpeed + 1f;

            if (_speedButton != null)
            {
                Text textComponent = _speedButton.GetComponentInChildren<Text>();
                if (textComponent != null)
                {
                    textComponent.text = $"{newSpeed}x";
                }
            }
        }

        private void OnUpgradeClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Upgrade();
                UpdateTowerInfo();
            }
        }

        private void OnSellClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Sell();
                HideTowerInfo();
            }
        }

        #endregion

        #region Game State

        private void OnGameStateChanged(GameState state)
        {
            switch (state)
            {
                case GameState.Paused:
                    ShowPauseMenu();
                    break;
                case GameState.Playing:
                    HidePauseMenu();
                    break;
                case GameState.GameOver:
                    ShowGameOver();
                    break;
                case GameState.Victory:
                    ShowVictory();
                    break;
            }
        }

        private void ShowPauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(true);
            }
        }

        private void HidePauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(false);
            }
        }

        private void ShowGameOver()
        {
            if (_gameOverPanel != null)
            {
                _gameOverPanel.SetActive(true);
            }
        }

        private void ShowVictory()
        {
            if (_victoryPanel != null)
            {
                _victoryPanel.SetActive(true);
            }
        }

        #endregion

        #region Wave Timer

        public void UpdateWaveTimer(float time)
        {
            if (_waveTimerText != null)
            {
                if (time > 0)
                {
                    _waveTimerText.text = $"Next Wave: {Mathf.CeilToInt(time)}s";
                }
                else
                {
                    _waveTimerText.text = "Wave In Progress";
                }
            }
        }

        public void UpdateEnemyCount(int count)
        {
            if (_enemyCountText != null)
            {
                _enemyCountText.text = $"Enemies: {count}";
            }
        }

        #endregion
    }
}

using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Map;

namespace TowerDefense.Core
{
    public enum GameState
    {
        Menu,
        Playing,
        Paused,
        GameOver,
        Victory
    }

    public class GameManager : Singleton<GameManager>
    {
        [Header("Level Config")]
        [SerializeField] private LevelData[] _levels;
        [SerializeField] private LevelBuilder _levelBuilder;

        [Header("Game Settings")]
        [SerializeField] private int _initialGold = 500;
        [SerializeField] private int _initialLife = 20;
        [SerializeField] private float _gameSpeed = 1f;

        [Header("Debug")]
        [SerializeField] private bool _debugMode = false;

        private LevelData _currentLevelData;

        private GameState _currentState = GameState.Menu;
        private int _currentGold;
        private int _currentLife;
        private int _currentWave = 0;
        private int _totalWaves = 0;
        private int _enemiesKilled = 0;
        private float _gameTime = 0f;

        public GameState CurrentState => _currentState;
        public int CurrentGold => _currentGold;
        public int CurrentLife => _currentLife;
        public int CurrentWave => _currentWave;
        public int TotalWaves => _totalWaves;
        public int EnemiesKilled => _enemiesKilled;
        public float GameTime => _gameTime;
        public float GameSpeed => _gameSpeed;
        public bool IsPlaying => _currentState == GameState.Playing;

        public System.Action<GameState> OnStateChanged;
        public System.Action<int> OnGoldChanged;
        public System.Action<int> OnLifeChanged;
        public System.Action<int> OnWaveChanged;

        protected override void Awake()
        {
            base.Awake();
            InitializeGame();
        }

        public LevelData CurrentLevelData => _currentLevelData;
        public LevelData[] Levels => _levels;

        private void Start()
        {
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "GameScene")
            {
                LoadLevel(0);
            }
        }

        public void LoadLevel(int levelIndex)
        {
            if (_levels == null || levelIndex < 0 || levelIndex >= _levels.Length)
            {
                Debug.LogError($"Invalid level index: {levelIndex}");
                return;
            }

            _currentLevelData = _levels[levelIndex];
            _initialGold = _currentLevelData.initialGold;
            _initialLife = _currentLevelData.initialLife;
            InitializeGame();

            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = 0 });
            OnLifeChanged?.Invoke(_currentLife);

            if (_levelBuilder != null)
            {
                _levelBuilder.BuildLevel(_currentLevelData);
            }

            StartGame(_currentLevelData.waves.Count > 0 ? _currentLevelData.waves.Count : _currentLevelData.waveCount);
        }

        private void InitializeGame()
        {
            _currentGold = _initialGold;
            _currentLife = _initialLife;
            _currentState = GameState.Menu;
            _currentWave = 0;
            _enemiesKilled = 0;
            _gameTime = 0f;
        }

        private void Update()
        {
            if (_currentState == GameState.Playing)
            {
                _gameTime += Time.deltaTime * _gameSpeed;
            }

            if (_debugMode)
            {
                HandleDebugInput();
            }
        }

        public void StartGame(int totalWaves)
        {
            _totalWaves = totalWaves;
            _currentState = GameState.Playing;
            _gameTime = 0f;
            Time.timeScale = _gameSpeed;
            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameStartEvent());
        }

        public void PauseGame()
        {
            if (_currentState == GameState.Playing)
            {
                _currentState = GameState.Paused;
                Time.timeScale = 0f;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = true });
            }
        }

        public void ResumeGame()
        {
            if (_currentState == GameState.Paused)
            {
                _currentState = GameState.Playing;
                Time.timeScale = _gameSpeed;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = false });
            }
        }

        public void TogglePause()
        {
            if (_currentState == GameState.Playing)
            {
                PauseGame();
            }
            else if (_currentState == GameState.Paused)
            {
                ResumeGame();
            }
        }

        public void GameOver(bool isVictory)
        {
            _currentState = isVictory ? GameState.Victory : GameState.GameOver;
            Time.timeScale = 0f;
            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameOverEvent { IsVictory = isVictory });
        }

        public void OnVictory()
        {
            GameOver(true);
        }

        public void RestartGame()
        {
            InitializeGame();
            Time.timeScale = 1f;
            UnityEngine.SceneManagement.SceneManager.LoadScene(
                UnityEngine.SceneManagement.SceneManager.GetActiveScene().name
            );
        }

        #region Gold Management

        public bool HasEnoughGold(int amount)
        {
            return _currentGold >= amount;
        }

        public void AddGold(int amount)
        {
            if (amount <= 0) return;
            _currentGold += amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = amount });
        }

        public bool SpendGold(int amount)
        {
            if (!HasEnoughGold(amount)) return false;
            _currentGold -= amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = -amount });
            return true;
        }

        #endregion

        #region Life Management

        public void TakeDamage(int damage)
        {
            _currentLife -= damage;
            if (_currentLife < 0) _currentLife = 0;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = -damage });

            if (_currentLife <= 0)
            {
                GameOver(false);
            }
        }

        public void Heal(int amount)
        {
            _currentLife += amount;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = amount });
        }

        #endregion

        #region Wave Management

        public void SetCurrentWave(int wave)
        {
            _currentWave = wave;
            OnWaveChanged?.Invoke(_currentWave);
        }

        public void IncrementWave()
        {
            _currentWave++;
            OnWaveChanged?.Invoke(_currentWave);
        }

        #endregion

        #region Statistics

        public void AddKill()
        {
            _enemiesKilled++;
        }

        #endregion

        #region Debug

        private void HandleDebugInput()
        {
            if (Input.GetKeyDown(KeyCode.F1))
            {
                AddGold(100);
                Debug.Log($"[Debug] Added 100 gold. Current: {_currentGold}");
            }
            if (Input.GetKeyDown(KeyCode.F2))
            {
                _currentLife = _initialLife;
                OnLifeChanged?.Invoke(_currentLife);
                Debug.Log($"[Debug] Life restored to {_currentLife}");
            }
            if (Input.GetKeyDown(KeyCode.F3))
            {
                _gameSpeed = _gameSpeed >= 3f ? 1f : _gameSpeed + 0.5f;
                if (_currentState == GameState.Playing)
                {
                    Time.timeScale = _gameSpeed;
                }
                Debug.Log($"[Debug] Game speed: {_gameSpeed}x");
            }
        }

        #endregion
    }
}

