args.script:
using UnityEngine;
using UnityEngine.UI;
using TowerDefense.UI;

var canvas = GameObject.Find("Canvas");
if (canvas == null) { Debug.LogError("Canvas not found"); return; }

var menuUI = canvas.GetComponent<MainMenuUI>();
if (menuUI == null) { Debug.LogError("MainMenuUI not found on Canvas"); return; }

// Find the existing objects in the 头像 area
var levelText = canvas.transform.Find("Panel/头像/Text (Legacy)");
var expSlider = canvas.transform.Find("Panel/头像/升级条");

if (levelText == null) { Debug.LogError("Level Text not found"); return; }
if (expSlider == null) { Debug.LogError("Exp Slider not found"); return; }

var textComp = levelText.GetComponent<Text>();
var sliderComp = expSlider.GetComponent<Slider>();

if (textComp == null) { Debug.LogError("Text component not found"); return; }
