private void OnLifeChanged(LifeChangedEvent e)
{
    UpdateLifeDisplay(e.CurrentLife);
}

private void OnExpChanged(ExpChangedEvent e)
{
    UpdateExpDisplay(e.CurrentExp, e.ExpToNext);
}

private void OnLevelUp(LevelUpEvent e)
{
    UpdateLevelDisplay(e.NewLevel);
}

private void UpdateLevelDisplay(int level)
{
    if (_levelText != null)
        _levelText.text = $"Lv.{level}";
}

private void UpdateExpDisplay(int currentExp, int expToNext)
{
    if (_expSlider != null)
    {
        _expSlider.maxValue = expToNext;
        _expSlider.value = currentExp;
    }
}

